# -*- coding: utf-8 -*-
AI_HPC = [
    {"hero":True,"sub":"AI/HPC Stocks & Infrastructure","h3":"OpenAI and Broadcom unveil first custom chip Jalapeno","summary":"OpenAI revealed Jalapeno, its first in-house AI accelerator built with Broadcom and aimed squarely at cutting the cost of running large models.","body":["OpenAI and Broadcom debuted Jalapeno, an inference-focused processor the companies describe as the first step in a multi-generation compute platform. Broadcom CEO Hock Tan personally delivered engineering samples to Sam Altman and Greg Brockman at OpenAI's San Francisco headquarters.","The chip went from initial design to tape-out in roughly nine months, which the companies call possibly the fastest high-performance ASIC cycle ever. Broadcom says early testing shows cost savings of around 50 percent versus typical AI GPUs, with first deployments planned by the end of 2026."],"sources":[("TechCrunch","https://techcrunch.com/2026/06/24/openai-unveils-its-first-custom-chip-built-by-broadcom/"),("VentureBeat","https://venturebeat.com/infrastructure/openai-unveils-first-custom-ai-inference-chip-jalapeno-with-broadcom-and-its-development-was-sped-up-with-openais-own-models")]},
    {"sub":"AI/HPC Stocks & Infrastructure","h3":"Anthropic locks in 3.5GW of Google and Broadcom compute","summary":"Anthropic expanded its deal with Google and Broadcom for multiple gigawatts of next-generation TPU capacity starting in 2027.","body":["Anthropic signed a new agreement giving it access to roughly 3.5 gigawatts of compute through Broadcom, on top of the 1 gigawatt already coming online in 2026. The company calls it a 4.5x expansion of its compute base inside 18 months, with most of the buildout in the United States.","The move deepens Anthropic's alignment with Google's TPU stack while rivals like OpenAI and Meta lean on Nvidia. Anthropic cited surging Claude demand, noting run-rate revenue has passed 30 billion dollars, up from around 9 billion at the end of 2025."],"sources":[("Anthropic","https://www.anthropic.com/news/google-broadcom-partnership-compute"),("Data Center Knowledge","https://www.datacenterknowledge.com/data-center-chips/anthropic-secures-multi-gigawatt-tpu-deal-with-google-broadcom")]},
    {"sub":"AI/HPC Stocks & Infrastructure","h3":"TSMC stock jumps as AI pricing power lifts targets","summary":"Taiwan Semiconductor shares rose on reports of advanced-node price hikes and a raised Bank of America target driven by AI demand.","body":["TSMC stock climbed as reports suggested the foundry could raise prices 5 to 10 percent on advanced 5nm, 4nm and 3nm production. Bank of America lifted its price target to 590 dollars from 490 and kept a Buy rating.","The company raised its 2026 full-year revenue growth forecast to more than 30 percent in dollar terms after first-quarter revenue rose 35 percent year over year. TSMC continues to manufacture chips for Nvidia, AMD, Apple and a growing roster of custom accelerator developers."],"sources":[("FX Leaders","https://www.fxleaders.com/news/2026/06/25/taiwan-semiconductor-stock-tsm-gains-5-as-ai-pricing-power-and-bofas-590-target-lift-sentiment/")]},
    {"sub":"AI/HPC Stocks & Infrastructure","h3":"Oracle to deploy 50,000 AMD MI450 GPUs in 2026","summary":"Oracle and AMD will stand up an AI supercluster of 50,000 next-generation Instinct MI450 GPUs using AMD's Helios rack design.","body":["AMD and Oracle agreed to deploy 50,000 MI450 Instinct GPUs alongside next-generation Epyc CPUs as part of an AI supercluster for Oracle's cloud. The deployment is set to become publicly available in the third quarter of 2026 and expand in 2027.","The cluster uses AMD's Helios rack architecture, the Venice-codenamed Epyc CPUs and Pensando networking. The MI450 is built to offer up to 432GB of HBM4 memory and 20 TB/s of bandwidth for very large models."],"sources":[("Tom's Hardware","https://www.tomshardware.com/tech-industry/artificial-intelligence/amd-and-oracle-partner-to-deploy-50-000-mi450-instinct-gpus-in-new-ai-superclusters-deployment-of-expansion-set-for-2026-powered-by-amds-helios-rack"),("Data Center Dynamics","https://www.datacenterdynamics.com/en/news/oracle-to-deploy-cluster-of-50000-amd-instinct-mi450-gpus/")]},
    {"sub":"AI/HPC Stocks & Infrastructure","h3":"Texas data center boom hits record construction spend","summary":"Data center construction spending has surged past last year's pace, with Texas now the world's top market and gigawatt-scale campuses breaking ground.","body":["Year-to-date data center construction spending through April 2026 reached 49.5 billion dollars, up from 13.6 billion in the same period a year earlier. Texas overtook Northern Virginia as the world's top primary data center market in May.","CloudBurst Data Centers broke ground in June on a 1.2 gigawatt campus in Central Texas, one of the largest single-site projects announced in North America. Vantage is planning a 1.4 gigawatt, 25 billion dollar campus in Shackelford County."],"sources":[("Westside Construction Group","https://www.buildwcg.com/blog-posts/data-center-power-grid-construction-ai-infrastructure-2026")]},
    {"sub":"AI/HPC Stocks & Infrastructure","h3":"FERC orders grid operators to fast-track AI data centers","summary":"Federal regulators told major grid operators to speed interconnection for data centers as power becomes the key bottleneck for AI buildouts.","body":["The Federal Energy Regulatory Commission directed six major grid operators to show that data centers can connect to the transmission system in a timely and orderly way, effectively creating a fast lane for AI campuses. The Department of Energy also launched a simulation platform called Agora to model hyperscale loads on a strained grid.","High-voltage substations now face lead times of three to five years, pushing developers toward bring-your-own-power models. Bloom Energy received an Oracle order for up to 2.85 gigawatts of on-site power generation."],"sources":[("TechCrunch","https://techcrunch.com/2026/06/18/ai-data-centers-just-got-a-government-mandated-fast-lane-to-the-grid/"),("Data Center Knowledge","https://www.datacenterknowledge.com/energy-power-supply/doe-is-quietly-building-the-ai-grid-operating-system")]},
    {"sub":"AI/HPC Stocks & Infrastructure","h3":"Nvidia rolls out fully liquid-cooled Rubin platform","summary":"Nvidia detailed a Rubin platform that liquid-cools every chip and networking component, running coolant warm enough to skip extra chilling.","body":["Nvidia said its Rubin platform is the first to fully liquid-cool every chip and networking component in a closed loop with no fans. The newest AI servers can run cooling liquid at up to 45 degrees Celsius, raising energy efficiency by reducing the need for separate chillers.","The company unveiled the approach around London Climate Week and argued the higher coolant temperature largely solves AI's water-use challenge. Nvidia also updated its data center roadmap following the LPU launch at GTC 2026."],"sources":[("NVIDIA Blog","https://blogs.nvidia.com/blog/liquid-cooling-ai-factories/"),("Axios","https://www.axios.com/2026/06/22/nvidia-data-center-water-solution")]},
    {"sub":"Foundation Models & Releases","h3":"OpenAI previews GPT-5.6 under government restrictions","summary":"OpenAI began a limited preview of its GPT-5.6 series, with Sol, Terra and Luna models released only to roughly 20 approved companies.","body":["OpenAI rolled out GPT-5.6 on Friday but limited access to all three variants at the request of the US government. Sol is the flagship, Terra a balanced everyday model and Luna a fast, low-cost option, with Terra priced at roughly half of GPT-5.5.","GPT-5.6 Sol advances coding, scientific reasoning, long-horizon planning and agentic workflows, and adds new max and ultra reasoning modes that lean on subagents. OpenAI plans broader availability in the coming weeks."],"sources":[("Axios","https://www.axios.com/2026/06/26/openai-gpt-sol-terra-luna-trump"),("9to5Mac","https://9to5mac.com/2026/06/26/openai-upgrading-chatgpt-and-codex-with-new-gpt-5-6-models-in-limited-release/")]},
    {"sub":"Foundation Models & Releases","h3":"Microsoft ships its own MAI models to cut OpenAI reliance","summary":"Microsoft unveiled in-house models including a code generator and its first reasoning model to lower developer costs and reduce dependence on OpenAI.","body":["Microsoft announced MAI-Code-1-Flash, which turns written descriptions into source code for apps and websites, and MAI-Thinking-1, its first reasoning model with 35 billion active parameters and a 256,000-token context window. The reasoning model targets complex multi-step instructions and long-context work.","The launch is part of Microsoft's push to lessen reliance on OpenAI and lower costs for developers, putting it in direct competition with both OpenAI and Anthropic in coding models."],"sources":[("CNBC","https://www.cnbc.com/2026/06/02/microsoft-unveils-new-ai-models-lessen-reliance-on-openai-lower-costs.html"),("Euronews","https://www.euronews.com/next/2026/06/03/microsoft-launches-its-own-ai-models-to-take-on-openai-and-anthropic")]},
    {"sub":"Foundation Models & Releases","h3":"Meta's Muse Spark now powers Meta AI assistant","summary":"Meta Superintelligence Labs shipped Muse Spark, its most powerful model to date, as it races to catch Google and OpenAI.","body":["Meta Superintelligence Labs released Muse Spark, originally code-named Avocado, as the first of its Muse series and the model now powering the Meta AI app and website. Meta plans to extend it across WhatsApp, Instagram, Facebook, Messenger and smart glasses.","The release follows Meta's 14 billion dollar deal to bring in Alexandr Wang and an AI capex budget of 115 to 135 billion dollars for 2026, nearly double last year's. Meta is also deploying custom AMD MI450-based GPUs starting in the second half of 2026."],"sources":[("eWEEK","https://www.eweek.com/news/meta-internal-ai-key-models/"),("CNBC","https://www.cnbc.com/2026/04/08/meta-debuts-first-major-ai-model-since-14-billion-deal-to-bring-in-alexandr-wang.html")]},
    {"sub":"Foundation Models & Releases","h3":"Google ships Gemini 3.5 Flash as 3.5 Pro looms","summary":"Gemini 3.5 Flash went generally available as the default in the Gemini app and Search, while a more powerful 3.5 Pro is expected to follow.","body":["Gemini 3.5 Flash shipped at Google I/O 2026 and serves as the default in the Gemini app and AI Mode in Search, with API pricing at 1.50 and 9.00 dollars per million input and output tokens. Sundar Pichai signaled Gemini 3.5 Pro would arrive soon after.","June is shaping up as one of the busiest model-release months of the year, with multiple flagship updates from major labs landing within weeks of each other."],"sources":[("WaveSpeed","https://wavespeed.ai/blog/posts/june-2026-ai-launch-wave/")]},
    {"sub":"Foundation Models & Releases","h3":"Microsoft and Google challenge rivals in coding models","summary":"Microsoft and Google both pushed new AI coding models in early June, escalating competition with Anthropic and OpenAI in software development.","body":["Microsoft and Google moved to take on Anthropic and OpenAI directly in AI coding models, a segment where Claude and OpenAI's Codex have led. The push reflects how central code generation has become to enterprise AI revenue.","The competition arrives as coding agents mature from pair-programming assistants toward more autonomous workflows, raising the stakes for whichever lab can pair model quality with cost efficiency."],"sources":[("CNBC","https://www.cnbc.com/2026/06/01/microsoft-and-google-take-on-anthropic-and-openai-in-ai-coding-models.html")]},
    {"sub":"Chinese AI Ecosystem","h3":"DeepSeek V4 lands with Huawei Ascend backing","summary":"DeepSeek launched preview versions of V4-Pro and V4-Flash, claiming top open-model math and coding scores and leaning on Huawei chips for compute.","body":["DeepSeek unveiled preview versions of DeepSeek-V4-Pro and V4-Flash, touting major upgrades in reasoning and agentic abilities such as autonomously writing code. The company said V4-Pro beats all rival open models on math and coding and trails only Google's closed Gemini 3.1-Pro on world knowledge.","To meet V4's compute needs, DeepSeek partnered with Huawei, which combines large clusters of its Ascend 950 chips through Supernode technology. Reports suggest DeepSeek is seeking fresh funding at a valuation above 20 billion dollars."],"sources":[("CNN","https://edition.cnn.com/2026/04/24/tech/chinas-ai-deepseek-v4-intl-hnk"),("Al Jazeera","https://www.aljazeera.com/economy/2026/4/24/chinas-deepseek-unveils-latest-model-a-year-after-upending-global-tech")]},
    {"sub":"Chinese AI Ecosystem","h3":"Anthropic accuses Alibaba of illicitly distilling Claude","summary":"Anthropic told US senators that an Alibaba-linked campaign used about 25,000 fake accounts and 28.8 million interactions to harvest Claude's capabilities.","body":["Anthropic accused operators linked to Alibaba's Qwen lab of running a large-scale effort to illicitly access Claude, targeting its software engineering and agentic reasoning. The company said the campaign ran from April 22 to June 5 2026 and involved nearly 25,000 fraudulent accounts generating over 28.8 million interactions.","Anthropic described the technique as adversarial distillation, in which an outside party repeatedly prompts an advanced model to harvest its reasoning patterns for training a rival. Anthropic called it the biggest such attempt yet by a Chinese company."],"sources":[("Bloomberg","https://www.bloomberg.com/news/articles/2026-06-24/anthropic-accuses-alibaba-of-illicitly-accessing-its-ai-models"),("Tom's Hardware","https://www.tomshardware.com/tech-industry/artificial-intelligence/anthropic-claims-that-chinas-alibaba-illicitly-distilled-its-models-from-april-to-june-2026-says-effort-involved-25-000-fake-accounts-and-28-8-million-exchanges-on-claude")]},
    {"sub":"Chinese AI Ecosystem","h3":"Alibaba ships Qwen3.7-Plus agent model, drops open weights","summary":"Alibaba made Qwen3.7-Plus generally available, adding vision, deep reasoning and tool use while breaking from its open-weight tradition.","body":["Alibaba released Qwen3.7-Plus on its Bailian platform, a multimodal model that understands images and video and adds deep reasoning, self-programming, tool invocation and autonomous iteration. It is priced at roughly one-sixth the per-token cost of Qwen 3.7 Max.","Notably, the model ships proprietary and API-only, breaking the lab's open-weight habit. The release builds on Alibaba's May unveiling of the Qwen3.7 generation, which included the text-only Qwen3.7-Max."],"sources":[("MarkTechPost","https://www.marktechpost.com/2026/06/02/alibabas-qwen-team-launches-qwen3-7-plus-adding-vision-deep-reasoning-tool-invocation-and-autonomous-iteration-on-the-bailian-platform/")]},
    {"sub":"Chinese AI Ecosystem","h3":"Moonshot launches Kimi Work desktop agent globally","summary":"Moonshot AI rolled out Kimi Work, a desktop agent built on its K2.6 model, as Chinese labs pivot hard toward autonomous agents.","body":["Moonshot launched Kimi Work, a desktop agent powered by its K2.6 Agent model with file system mounting, scheduled cron execution and a browser automation layer. It includes native market data feeds for A-share, Hong Kong and US equities, positioning it against OpenAI's ChatGPT Agent and Claude for Chrome.","Moonshot raised about 2 billion dollars at a 20 billion dollar valuation in a Meituan-led round and has held talks about raising more. Its Kimi K2.6 ranks as one of the most used models on the OpenRouter platform."],"sources":[("Business 2.0","https://business20channel.tv/moonshot-ai-launches-kimi-work-desktop-agent-globally-in-2026-24-06-2026"),("TechCrunch","https://techcrunch.com/2026/05/07/chinas-moonshot-ai-raises-2b-at-20b-valuation-as-demand-for-open-source-ai-skyrockets/")]},
    {"sub":"Chinese AI Ecosystem","h3":"Huang calls smuggled-chip data centers a dead end","summary":"Nvidia CEO Jensen Huang told shareholders that data centers built from smuggled parts cannot succeed without official support and repairs.","body":["Jensen Huang said that companies trying to smuggle Nvidia chips into export-restricted countries like China would hit a dead end because Nvidia would not provide support or repairs. He told shareholders that national security comes first when commercial opportunity conflicts with US interests.","The comments come as Washington keeps tight controls on advanced AI hardware exports and Chinese firms increasingly turn to domestic alternatives such as Huawei's Ascend chips."],"sources":[("CNBC","https://www.cnbc.com/2026/06/24/nvidia-huang-data-center-smuggled-chips.html")]},
    {"sub":"Agents & Automation","h3":"Cognition's Devin raises at 26 billion dollar valuation","summary":"Cognition raised 1 billion dollars at a 26 billion dollar valuation, betting its autonomous Devin agent can beat IDE-first coding tools.","body":["Cognition's raise prices its autonomous Devin agent at a 53x revenue multiple, above Cursor's 30x even though Cursor earns roughly four times more. The bet is that fully autonomous task delegation will outlast assistant-style tools that keep the engineer in the loop.","Cognition rebranded Windsurf as Devin Desktop after acquiring it. The company reports a 67 percent pull-request merge rate, up from 34 percent a year earlier, and says Devin writes 89 percent of its own commits."],"sources":[("TechTimes","https://www.techtimes.com/articles/317354/20260529/ai-coding-agents-cognitions-26b-raise-bets-agent-first-architecture-beats-ide-tools.htm"),("MarkTechPost","https://www.marktechpost.com/2026/06/10/ai-coding-agents-development-platforms-2026/")]},
    {"sub":"Agents & Automation","h3":"Microsoft makes Copilot Cowork agents generally available","summary":"Microsoft brought Copilot Cowork to general availability worldwide, embedding agentic AI into everyday Microsoft 365 workflows.","body":["Microsoft made Copilot Cowork generally available globally, pushing agentic AI into the daily workflows of organizations already running Microsoft 365. The move follows Microsoft Build 2026, which the company framed as the start of the agentic AI era for enterprises.","The rollout reflects a broader shift across major vendors from chat assistants toward agents that can carry out multi-step tasks inside business software."],"sources":[("EPC Group","https://www.epcgroup.net/blog/microsoft-build-2026-agentic-ai-era-what-cios-must-do-now")]},
    {"sub":"Agents & Automation","h3":"Anthropic brings Claude into Slack as a team member","summary":"Anthropic launched Claude Tag, letting teams add Claude directly into their Slack workspace as a shared collaborator.","body":["Anthropic launched Claude Tag, a feature that brings Claude into a Slack workspace as a shared team member that colleagues can call on directly. The launch is part of Anthropic's broader enterprise push.","Anthropic said Claude reached 56 million monthly active users in the second quarter, with year-over-year growth of roughly 640 percent, underscoring rapid adoption of its agent and assistant products."],"sources":[("SoftSnow","https://softsnow.ai/blog-posts/anthropic-openai-microsoft-june-2026")]},
    {"sub":"Agents & Automation","h3":"OpenAI launches partner network for enterprise AI delivery","summary":"OpenAI introduced a 150 million dollar partner network to help consultancies and integrators build and deliver AI, certifying 300,000 consultants by year-end.","body":["OpenAI announced the OpenAI Partner Network, a structured program for consulting firms, systems integrators and technology companies to build, sell and deliver AI solutions alongside it. The company is investing 150 million dollars and aims to certify 300,000 AI consultants by the end of 2026.","OpenAI argued the limiting factor for enterprise AI value is no longer model capability but deployment, signaling a new phase in the enterprise AI race against Anthropic and others."],"sources":[("CIO","https://www.cio.com/article/4167787/openai-anthropic-expand-services-push-signaling-new-phase-in-enterprise-ai-race.html")]},
    {"sub":"Enterprise & Regulation","h3":"EU delays high-risk AI Act rules in Digital Omnibus","summary":"The EU Parliament passed amendments delaying high-risk AI provisions while transparency obligations still take effect in August 2026.","body":["On June 16 2026 the EU Parliament passed amendments approving the Digital Omnibus, moving high-risk uses listed in Annex III from August 2026 to December 2027. Those uses cover employment, education, credit scoring, biometric ID, critical infrastructure, law enforcement, migration and justice.","Transparency obligations under Article 50 still apply from August 2 2026, requiring disclosure for certain AI functionalities. The Commission also appointed a 60-member scientific panel and published a voluntary code of practice on labeling AI-generated content."],"sources":[("Sidley Data Matters","https://datamatters.sidley.com/2026/06/24/eu-ai-act-transparency-obligations-preparing-for-compliance-by-2-august-2026/"),("Latham & Watkins","https://www.lw.com/en/insights/ai-act-update-eu-resolves-to-change-rules-and-extend-deadlines")]},
    {"sub":"Enterprise & Regulation","h3":"Trump signs AI innovation and security executive order","summary":"President Trump issued an executive order on advanced AI innovation and security carrying forward priorities from his earlier cyber strategy.","body":["On June 2 2026 President Trump issued the executive order Promoting Advanced Artificial Intelligence Innovation and Security. It carries forward several priorities from the Cyber Strategy for America released in March 2026.","The order lands alongside the government's role in restricting GPT-5.6 access to a small set of approved companies, signaling tighter federal involvement in how frontier models are released and secured."],"sources":[("Collibra","https://www.collibra.com/blog/ai-regulatory-compliance-in-2026-eu-ai-act-us-orders-and-state-laws-and-how-to-operationalize")]},
    {"sub":"Enterprise & Regulation","h3":"Google bleeds top AI researchers to Anthropic and OpenAI","summary":"A wave of senior Google researchers is leaving for Anthropic and OpenAI, rattling investors and raising doubts about DeepMind's edge.","body":["Gemini researchers Jonas Adler and Alexander Pritzel are leaving Google for Anthropic, making four senior exits in six days. Earlier departures included Nobel laureate John Jumper heading to Anthropic and star researcher Noam Shazeer joining OpenAI on June 18.","The moves rattled Alphabet investors and cast doubt on Google's ability to keep pace in the model race. Analysts note the pull of pre-IPO equity at Anthropic and OpenAI as a powerful draw for Big Tech talent."],"sources":[("TechCrunch","https://techcrunch.com/2026/06/24/ai-researchers-continue-to-leave-google-for-its-rivals/"),("Bloomberg","https://www.bloomberg.com/news/articles/2026-06-24/google-poised-to-lose-two-more-high-profile-ai-staffers-to-anthropic")]},
    {"sub":"Enterprise & Regulation","h3":"Anthropic files confidentially for IPO after 65 billion raise","summary":"Anthropic filed confidentially for an IPO days after a 65 billion dollar Series H round pushed its valuation near 965 billion dollars.","body":["Anthropic filed confidentially for an initial public offering on June 1, just after raising 65 billion dollars in a Series H round that lifted its valuation to roughly 965 billion. The filing signals one of the largest AI public offerings on the horizon.","The pre-IPO momentum is part of why Anthropic and OpenAI are attracting senior researchers from rivals, offering employees a rare chance at a payday by signing on before going public."],"sources":[("SoftSnow","https://softsnow.ai/blog-posts/anthropic-openai-microsoft-june-2026")]},
]
